const item = $input.first().json;
const body = item.body || item;
const data = body.data || {};
const key = data.key || {};
const msg = data.message || {};

const pushName = data.pushName || body.pushName || "";
const remetente = key.remoteJid || body.remoteJid || body.sender || "";
const fromMe = key.fromMe === true;
const mensagem = msg.conversation
  || msg.extendedTextMessage?.text
  || msg.imageMessage?.caption
  || msg.documentMessage?.caption
  || msg.videoMessage?.caption
  || "";
const msgType = data.messageType || "";
const destinatario = body.sender || "";

return [{
  json: {
    pushName,
    remetente,
    fromMe,
    msg: mensagem,
    msgType,
    destinatario
  }
}];

const extItems = $items("Extrair dados");
const extData = (extItems && extItems.length > 0) ? extItems[0].json : {};

// Filtra mensagens enviadas por nos (fromMe = true)
if (extData.fromMe === true) {
  return [null];
}

const msg = extData.msg || "";
// Filtra mensagens vazias
if (!msg || msg.trim() === "") {
  return [null];
}

const apiData = $input.first().json;
const remetente = extData.remetente || "";

// Extrai o numero limpo (sem @s.whatsapp.net, @lid, etc)
const numero = remetente.split("@")[0] || remetente;

return [{
  json: {
    remetente: remetente,
    numero: numero,
    pushName: extData.pushName || "",
    msg: msg,
    msgType: extData.msgType || "",
    estado: apiData.estado || "SAUDACAO",
    dados: apiData.dados || {},
    conversaId: apiData.id || null
  }
}];

const item = $input.first().json;
const aiRes = item.output || "";

const remetente = item.remetente || "";
const numero = item.numero || remetente.split("@")[0] || "";
const curEstado = item.estado || "SAUDACAO";
const curDados = item.dados || {};
const msgOriginal = item.msg || "";
const msg = msgOriginal.toLowerCase().trim();

let nextEstado = curEstado;
const dados = JSON.parse(JSON.stringify(curDados));
const palavrasNao = ["nao", "não", "n", "nem", "ñ", "no"];
const palavrasSim = ["sim", "sou", "s", "ss", "claro", "ok", "pode ser", "confirmo", "gostaria"];

function contem(lista, texto) {
  return lista.some(p => texto.includes(p));
}

function extrair(msgCmp, msgOrig) {
  const cnpj = msgOrig.match(/\d{2}\.?\d{3}\.?\d{3}\/?\d{4}-?\d{2}/);
  if (cnpj && !dados.documento) {
    dados.documento = cnpj[0];
    dados.tipoPessoa = "PJ";
  }
  const cpf = msgOrig.match(/\d{3}\.?\d{3}\.?\d{3}-?\d{2}/);
  if (cpf && !dados.documento) {
    dados.documento = cpf[0];
    dados.tipoPessoa = "PF";
  }
  const email = msgCmp.match(/[a-z0-9._%+-]+@[a-z0-9.-]+\.[a-z]{2,}/);
  if (email && !dados.email) dados.email = email[0];
  const fone = msgOrig.match(/(\d{2})\s?9?\d{3,4}-?\d{4}/);
  if (fone && !dados.telefone) dados.telefone = fone[0];
  if (!dados.nome && msgOrig.length > 3
      && !contem(palavrasNao, msgCmp)
      && !contem(palavrasSim, msgCmp)
      && !email
      && !cnpj && !cpf
      && msgCmp.replace(/[^a-záàãéêíóôúç ]/g,"").length > 3
      && msgCmp.replace(/[^a-záàãéêíóôúç ]/g,"").length > msgOrig.length * 0.3) {
    dados.nome = msgOrig;
  }
}

if (curEstado === "SAUDACAO") {
  nextEstado = "VALIDANDO_TIPO";

} else if (curEstado === "VALIDANDO_TIPO") {
  if (contem(palavrasNao, msg) || msg.includes("fisica") || msg.includes("física")) {
    dados.tipoPessoa = "PF";
  }
  if (msg.includes("cnpj") || msg.includes("empresa") || msg.includes("juridica") || msg.includes("pj")) {
    dados.tipoPessoa = "PJ";
  }
  if (contem(palavrasSim, msg) || msg.includes("cnpj") || msg.includes("cpf") || msg.includes("pf") || msg.includes("pj") || dados.tipoPessoa) {
    extrair(msg, msgOriginal);
    nextEstado = "COLETANDO_DADOS";
  }

} else if (curEstado === "COLETANDO_DADOS") {
  extrair(msg, msgOriginal);
  const temNome = dados.nome && dados.nome.length > 0;
  const temEmail = dados.email && dados.email.length > 0;
  const temDoc = dados.documento && dados.documento.length > 0;
  const temTel = dados.telefone && dados.telefone.length > 0;
  if (temNome && temEmail && temDoc && temTel) {
    nextEstado = "CONSULTANDO_PRODUTO";
  }

} else if (curEstado === "CONSULTANDO_PRODUTO") {
  dados.produto = msgOriginal;
  nextEstado = "FINALIZANDO";

} else if (curEstado === "FINALIZANDO") {
  dados.finalizado = true;
  nextEstado = "ENCERRADO";

} else if (curEstado === "ENCERRADO") {
}

return [{
  json: {
    remetente: remetente,
    numero: numero,
    pushName: item.pushName || "",
    msg: msgOriginal,
    resposta: aiRes || "Desculpe, nao entendi. Pode repetir?",
    estado: nextEstado,
    dados
  }
}];
